#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv1d_impl_npu(const at::Tensor& x, const at::Tensor& weight,
                           int64_t stride, int64_t padding, int64_t dilation, int64_t groups) {
    at::Tensor y = at::empty({x.size(0), weight.size(0),
                              (x.size(2) + 2 * padding - dilation * (weight.size(2) - 1) - 1) / stride + 1},
                              x.options());
    EXEC_NPU_CMD(aclnnConvStandard1dDilatedStridedCustom, x, weight, (int)stride, (int)padding, (int)dilation, (int)groups, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_standard_1d_dilated_strided_custom", &conv1d_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("conv_standard_1d_dilated_strided_custom",
          [](const at::Tensor& x, const at::Tensor& w) {
              return conv1d_impl_npu(x, w, 3, 0, 4, 1);
          },
          "Conv1d (dilated,strided) (ConvStandard1dDilatedStridedCustom on NPU)");
}
